import machine
import time
import network
from umqtt.simple import MQTTClient

# Wi-Fi configuration
WIFI_SSID = "your_wifi_ssid"
WIFI_PASSWORD = "your_wifi_password"

# MQTT broker configuration
MQTT_BROKER = "your_mqtt_broker_ip"  # e.g., "192.168.1.100" or "broker.hivemq.com"
MQTT_CLIENT_ID = "esp32_temp_sensor_01"
MQTT_TOPIC = "sensors/temp"

# --- Sensor setup (simulate for this example) ---
# For a real sensor, you would initialize and read from it here.
# Example: Using machine.ADC for analog sensor, or I2C/SPI for digital sensors.
def read_temperature():
    # Simulate reading a temperature sensor
    # In a real scenario, connect a sensor (e.g., DHT11, DS18B20, or an analog sensor via ADC)
    # For now, return a dummy temperature that changes slightly
    return 25.0 + (time.time() % 100) / 50 - 1

# --- Wi-Fi Connection ---
def connect_wifi():
    sta_if = network.WLAN(network.STA_IF)
    if not sta_if.isconnected():
        print(f"Connecting to WiFi: {WIFI_SSID}...")
        sta_if.active(True)
        sta_if.connect(WIFI_SSID, WIFI_PASSWORD)
        timeout = 10
        while not sta_if.isconnected() and timeout > 0:
            time.sleep(1)
            print(".", end="")
            timeout -= 1
        print("")
    if sta_if.isconnected():
        print(f"Wi-Fi connected! IP address: {sta_if.ifconfig()[0]}")
    else:
        print("Failed to connect to Wi-Fi.")
        machine.reset() # Reset if connection fails after timeout
    return sta_if

# --- Main Program ---
def main():
    # Connect to Wi-Fi
    connect_wifi()

    # Initialize MQTT Client
    client = MQTTClient(MQTT_CLIENT_ID, MQTT_BROKER)

    try:
        print(f"Connecting to MQTT broker: {MQTT_BROKER}...")
        client.connect()
        print("Connected to MQTT broker.")
    except Exception as e:
        print(f"Failed to connect to MQTT broker: {e}")
        # Optionally, try to reconnect or reset
        time.sleep(5)
        machine.reset()

    while True:
        try:
            temperature = read_temperature()
            payload = f"{temperature:.2f}"
            print(f"Publishing temperature: {payload} °C to topic: {MQTT_TOPIC}")
            client.publish(MQTT_TOPIC, payload)
            time.sleep(30) # Publish every 30 seconds

        except OSError as e:
            print(f"Failed to publish (OSError): {e}")
            print("Attempting to reconnect to MQTT...")
            try:
                client.connect()
                print("Reconnected to MQTT broker.")
            except Exception as reconnect_e:
                print(f"Failed to reconnect to MQTT: {reconnect_e}")
                print("Restarting ESP32...")
                time.sleep(5)
                machine.reset()
        except Exception as e:
            print(f"An unexpected error occurred: {e}")
            time.sleep(5) # Wait before trying again

if __name__ == "__main__":
    main()